const incoming = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const pick = (...vals) => {
  for (const v of vals) {
    if (v === undefined || v === null) continue;
    const str = typeof v === 'string' ? v.trim() : v;
    if (typeof str === 'string' && !str) continue;
    return str;
  }
  return '';
};
const video_url = pick(incoming.video_url, incoming.videoUrl, incoming.url);
const audio_url = pick(incoming.audio_url, incoming.audioUrl);
const finalUrl = video_url || audio_url;
const language = pick(incoming.language, incoming.lang, 'auto');
const taskId = pick(incoming.task_id, incoming.taskId, incoming.replication_id, incoming.replicationId);
return [{
  json: {
    task_id: taskId || null,
    video_url: finalUrl,
    request_language: language.toLowerCase(),
    raw: incoming
  }
}];

const items = $input.all();
const out = [];

// 尝试获取上游标准化输入的数据（使用 $node 语法跨节点获取数据）
let standardInput = {};
try {
    standardInput = $node['标准化输入'].item.json || {};
} catch(e) {
    // 容错：如果找不到上游节点，给个空对象
}
const rawInput = standardInput.raw || {};

for (const item of items) {
    // 获取 HTTP 节点返回的 JSON
    let cozeResponse = item.json || {};

    // 防御性编程：如果 n8n 把整个结果包成了一个数组 [ {code: 0 ...} ]，提取第一项
    if (Array.isArray(cozeResponse) && cozeResponse.length > 0) {
        cozeResponse = cozeResponse[0];
    }

    let transcript = "";
    let success = false;

    try {
        // 核心解析逻辑：判断状态码为 0，且 data 有内容
        if (cozeResponse.code === 0 && cozeResponse.data) {

            // data 是一个被包裹的 JSON 字符串，需要 JSON.parse 解包
            const parsedData = JSON.parse(cozeResponse.data);

            // 提取最终的 output 字段
            if (parsedData.output) {
               transcript = parsedData.output.trim();
               success = true;
            }
        }
    } catch (e) {
        console.error("解析 Coze 返回失败:", e);
    }

    // 计算字数估算 (简单除以 2 估算英文词数/中文词数)
    const charCount = transcript.replace(/\s+/g, '').length;
    const wordEstimate = charCount ? Math.max(1, Math.round(charCount / 2)) : 0;

    // 组装最终传给后端/前端的数据结构
    out.push({
        json: {
            success: success,
            transcript: transcript,
            words_estimate: wordEstimate,
            language: standardInput.request_language || 'auto',
            task_id: standardInput.task_id || null,
            callback_url: rawInput.callback_url || '',
            script_id: rawInput.script_id || '',
            reference_item_id: rawInput.reference_item_id || '',
            raw: cozeResponse // 保留原始数据方便后续排错
        }
    });
}

return out;
